defaultMarkers:
{{(() => {
     const markers = [];

     // Pickup marker
     if (NewPickupLatHidden.text && NewPickupLngHidden.text) {
       markers.push({
         lat: parseFloat(NewPickupLatHidden.text),
         long: parseFloat(NewPickupLngHidden.text),
         title: "Pickup: " + (NewPickupAddressInput.text || ""),
         color: "green"
       });
     }

     // Dropoff marker
     if (NewDropoffLatHidden.text && NewDropoffLngHidden.text) {
       markers.push({
         lat: parseFloat(NewDropoffLatHidden.text),
         long: parseFloat(NewDropoffLngHidden.text),
         title: "Delivery: " + (NewDropoffAddressInput.text || ""),
         color: "red"
       });
     }

     return markers;
   })()}}
